mapper.sql:
/* wms-inventory-invnrevision-sql-oracle.xml - selectInvnRevision - 재고 조정 조회 SQL */ SELECT '0' AS CHK , A.CTKEY , MAX(B.CTNAME) AS CTNAME , A.OWKEY , MAX(C.OWNAME) AS OWNAME , A.ICKEY , MAX(D.ICNAME) AS ICNAME , A.LCKEY , MAX(A.ULCKEY) AS ULCKEY , A.EXPIREDATE , MAX(A.IVATKEY) AS IVATKEY , A.UOM , ROUND(COALESCE(SUM(A.TTQTY), 0) / COALESCE(E.ICUTQTY, 1), 2) AS TTQTY_UNIT , ROUND(COALESCE(SUM(A.AVQTY), 0) / COALESCE(E.ICUTQTY, 1), 2) AS AVQTY_UNIT , ROUND(COALESCE(SUM(A.ALQTY), 0) / COALESCE(E.ICUTQTY, 1), 2) AS ALQTY_UNIT , ROUND(COALESCE(SUM(A.PAQTY), 0) / COALESCE(E.ICUTQTY, 1), 2) AS PAQTY_UNIT , ROUND(COALESCE(SUM(A.PIQTY), 0) / COALESCE(E.ICUTQTY, 1), 2) AS PIQTY_UNIT , ROUND(COALESCE(SUM(A.LOQTY), 0) / COALESCE(E.ICUTQTY, 1), 2) AS LOQTY_UNIT , ROUND(COALESCE(SUM(A.HOQTY), 0) / COALESCE(E.ICUTQTY, 1), 2) AS HOQTY_UNIT , COALESCE(SUM(A.TTQTY), 0) AS TTQTY , COALESCE(SUM(A.AVQTY), 0) AS AVQTY , COALESCE(SUM(A.ALQTY), 0) AS ALQTY , COALESCE(SUM(A.PAQTY), 0) AS PAQTY , COALESCE(SUM(A.PIQTY), 0) AS PIQTY , COALESCE(SUM(A.LOQTY), 0) AS LOQTY , COALESCE(SUM(A.HOQTY), 0) AS HOQTY , COALESCE(SUM(A.WCS_AVQTY), 0) AS WCS_AVQTY_UNIT , COALESCE(SUM(A.WCS_HOQTY), 0) AS WCS_HOQTY_UNIT , COALESCE(SUM(A.WCS_AVQTY), 0) * COALESCE(E.ICUTQTY, 1) AS WCS_AVQTY , COALESCE(SUM(A.WCS_HOQTY), 0) * COALESCE(E.ICUTQTY, 1) AS WCS_HOQTY , MAX(A.LOGGRPCD) AS LOGGRPCD , A.IVATSTATUS , (COALESCE(SUM(A.WCS_AVQTY), 0) * COALESCE(E.ICUTQTY, 1) * COALESCE(D.WEIGHT, 0)) + (COALESCE(SUM(A.WCS_HOQTY), 0) * COALESCE(E.ICUTQTY, 1) * COALESCE(D.WEIGHT, 0)) AS NET_WGT , MAX(A.INSERTDATE) AS INSERTDATE , MAX(A.INSERTURKEY) AS INSERTURKEY , MAX(A.UPDATEDATE) AS UPDATEDATE , MAX(A.UPDATEURKEY) AS UPDATEURKEY FROM ( SELECT A.CTKEY , A.OWKEY , A.LCKEY , A.ICKEY , A.ULCKEY , B.EXPIREDATE , A.IVATKEY , A.TTQTY , A.AVQTY , A.ALQTY , A.PAQTY , A.PIQTY , A.LOQTY , A.HOQTY , 0 AS WCS_HOQTY , 0 AS WCS_AVQTY , B.UOM , B.LOGGRPCD , B.IVATSTATUS , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TWORK_INFO_IVATXLCXULC A INNER JOIN TWORK_INFO_IVAT B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.IVATKEY = B.IVATKEY INNER JOIN TWORK_MST_LC C ON A.CTKEY = C.CTKEY AND A.LCKEY = C.LCKEY INNER JOIN TWORK_MST_AR D ON C.CTKEY = D.CTKEY AND C.ARKEY = D.ARKEY WHERE A.CTKEY = #{CTKEY} AND A.OWKEY = #{OWKEY}
AND A.ICKEY = #{ICKEY}
AND D.WRHOUS_SE = 'ATMC' AND (A.AVQTY > 0 OR A.HOQTY > 0) UNION ALL SELECT #{CTKEY} AS CTKEY , #{OWKEY} AS OWKEY , B.LOCATION_CODE AS LCKEY , B.CODE AS ICKEY , '' AS ULCKEY , REPLACE(B.EFFECTIVE_DATE, '-', '') || '000000' AS EXPIREDATE , NULL AS IVATKEY , 0 , 0 , 0 , 0 , 0 , 0 , 0 , CASE WHEN B.HOLD_STATUS = 'true' THEN QUANTITY_VALUE ELSE 0 END AS WCS_HOQTY , CASE WHEN B.HOLD_STATUS = 'false' THEN QUANTITY_VALUE ELSE 0 END AS WCS_AVQTY , B.QUANTITY_UNIT AS UOM , '' AS LOGGRPCD , CASE WHEN HOLD_STATUS = 'true' THEN '20' ELSE '10' END AS IVATSTATUS , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TWORK_INFO_STOCKSTATUS_REQ A INNER JOIN TWORK_INTF_RIVWCS B ON A.IV_NUMBER = B.IV_NUMBER WHERE A.REQUEST_DATE = #{IVDATE} AND A.CTKEY = #{CTKEY} AND 0 < (SELECT COUNT(*) FROM TWORK_INTF_RIVWCS RIVWCS WHERE STATUS IN('HEADTAIL', 'TAIL') AND RIVWCS.IV_NUMBER = B.IV_NUMBER)
AND B.CODE = #{ICKEY}
) A INNER JOIN TWORK_MST_CT B ON A.CTKEY = B.CTKEY INNER JOIN TWORK_MST_OW C ON A.OWKEY = C.OWKEY INNER JOIN TWORK_MST_IC D ON A.CTKEY = D.CTKEY AND A.OWKEY = D.OWKEY AND A.ICKEY = D.ICKEY INNER JOIN TWORK_MST_ICUTXTYPE E ON A.CTKEY = E.CTKEY AND A.OWKEY = E.OWKEY AND D.ICUTKEY = E.ICUTKEY AND A.UOM = E.ICUTTYPE GROUP BY A.CTKEY, A.OWKEY, A.ICKEY,A.LCKEY, A.EXPIREDATE, A.UOM, E.ICUTQTY, A.IVATSTATUS, D.WEIGHT

mapper.select:
#{GRIDPAGING_ROWNUMTYPE_TOP}




			ORDER BY #{colName} DESC


			ORDER BY #{colName} ASC



			ORDER BY A.ICKEY, A.EXPIREDATE


#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* wms-inventory-invnrevision-sql-oracle.xml - selectStockstatusReq - 재고 현황 요청 정보 조회  SQL */
	SELECT IV_NUMBER
	  FROM TWORK_INFO_STOCKSTATUS_REQ
	 WHERE CTKEY = #{ctkey}
	   AND OWKEY = #{owkey}
	   AND REQUEST_DATE = #{ivdate}

mapper.insert:
/* wms-inventory-invnrevision-sql-oracle.xml - insertStockstatusReq - 재고 현황 요청 정보 등록  SQL */
	 INSERT INTO TWORK_INFO_STOCKSTATUS_REQ
	 	  (
	 	    CTKEY
	 	  , OWKEY
	 	  , REQUEST_DATE
	 	  , IV_NUMBER
	 	  , INSERTDATE
	      , INSERTURKEY
	      , UPDATEDATE
	      , UPDATEURKEY
	 	  )
     VALUES
          (
            #{ctkey}
          , #{owkey}
          , #{ivdate}
          , #{ivNumber}
          , TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
	 	  , #{surkey}
	 	  , TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
	 	  , #{surkey}
          )

mapper.update:
/* wms-inventory-invnrevision-sql-oracle.xml - updateStockstatusReq - 재고 현황 요청 정보 수정  SQL */
	UPDATE TWORK_INFO_STOCKSTATUS_REQ
	   SET IV_NUMBER = #{ivNumber}
		 , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
		 , UPDATEURKEY = #{surkey}
	 WHERE CTKEY = #{ctkey}
	   AND OWKEY = #{owkey}
	   AND REQUEST_DATE = #{ivdate}

mapper.insert:
/* wms-inventory-invnrevision-sql-oracle.xml - insertTworkInfoIvat - 재고 속성 등록  SQL */
	INSERT INTO TWORK_INFO_IVAT
		 (
		 CTKEY
		 , IVATKEY
		 , OWKEY
		 , ICKEY
		 , PRODUCTDATE
		 , EXPIREDATE
		 , ATTRIBUTE1
		 , ATTRIBUTE2
		 , ATTRIBUTE3
		 , ATTRIBUTE4
		 , ATTRIBUTE5
		 , PRODUCTLOT
		 , IVATSTATUS
		 , IBCONFIRMDATE
		 , LOGGRPCD
		 , ACKEY
		 , STORE_KEY
		 , ATTRIBUTE6
		 , ATTRIBUTE7
		 , ATTRIBUTE8
		 , ATTRIBUTE9
		 , IDNTFC_NO
		 , BDDR_GNRL_ITEM_IBYN
		 , CON_QTY
		 , NET_WGT
		 , CFQTY
		 , PLT_TYPE
		 , PLT_LOAD_QTY
		 , PLT_LOAD_HEIGHT
		 , UOM
		 , INSERTDATE
		 , INSERTURKEY
		 , UPDATEDATE
		 , UPDATEURKEY
		 ) VALUES
		 (
		 #{ctkey}
		 , #{ivatkey}
		 , #{owkey}
		 , #{ickey}
		 , #{productdate}
		 , #{expiredate}
		 , '2'					/* TC/DC 구분 */
		 , '1'					/* 일반/보세 구분  */
		 , #{attribute3}
		 , #{attribute4}
		 , #{attribute5}
		 , #{productlot}
		 , #{ivatstatus}
		 , COALESCE(#{ibconfirmdate}, TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS'))
		 , COALESCE(#{loggrpcd}, '1')
		 , #{ackey}
		 , #{storeKey}
		 , #{attribute6}
		 , #{attribute7}
		 , #{attribute8}
		 , #{attribute9}
		 , #{idntfcNo}
		 , #{bddrGnrlItemIbyn}
		 , #{conQty}
		 , #{netWgt}
		 , #{cfqty}
		 , #{pltType}
		 , #{pltLoadQty}
		 , #{pltLoadHeight}
		 , #{uom}
		 , TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
		 , #{surkey}
		 , TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
		 , #{surkey}
		 )

mapper.update:
/* wms-inventory-invnrevision-sql-oracle.xml - updateInvnQty - 재고 수정  SQL */
	 UPDATE TWORK_INFO_IVATXLCXULC
	 	SET TTQTY = COALESCE(#{wcsAvqty}, 0) + COALESCE(#{alqty}, 0) + COALESCE(#{paqty}, 0) + COALESCE(#{piqty}, 0) + COALESCE(#{loqty}, 0) + COALESCE(#{wcsHoqty}, 0)
	 	  , HOQTY = COALESCE(#{wcsHoqty}, 0)
	 	  , AVQTY = COALESCE(#{wcsAvqty}, 0)
	 	  , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
	 	  , UPDATEURKEY = #{surkey}
	  WHERE CTKEY = #{ctkey}
	    AND OWKEY = #{owkey}
	    AND ICKEY = #{ickey}
	    AND LCKEY = #{lckey}
	    AND IVATKEY = #{ivatkey}

mapper.insert:
	/* wms-inbound-invnrevision-sql-oracle.xml - insertIvatxlculc - 입고반품 재고 등록  SQL */
    	INSERT INTO TWORK_INFO_IVATXLCXULC
				(
				  CTKEY
				, IVATKEY
				, LCKEY
				, ULCKEY
				, OWKEY
				, ICKEY
				, TTQTY
				, AVQTY
				, ALQTY
				, PIQTY
				, PAQTY
				, LOQTY
				, HOQTY
				, IVATSTATUS
				, INSERTDATE
				, INSERTURKEY
				, UPDATEDATE
				, UPDATEURKEY
				, LOGGRPCD
				)
		 VALUES (
				  #{ctkey}
				, #{ivatkey}
				, #{lckey}
				, COALESCE(#{ulckey}, 'NA')
				, #{owkey}
				, #{ickey}
				, COALESCE(#{wcsAvqty}, 0) + COALESCE(#{wcsHoqty}, 0)
				, COALESCE(#{wcsAvqty}, 0)
				, 0
				, 0
				, 0
				, 0
				, #{wcsHoqty}
				, #{ivatstatus}
				, #{sysdate}
	       		, #{surkey}
	       		, #{sysdate}
	       		, #{surkey}
				, #{loggrpcd}
				)

mapper.select:
/* wms-inventory-invnrevision-sql-oracle.xml - selectIvatxlcxulcAdjSeq - 재고 조정 이력 seq 조회 SQL */
	 SELECT COALESCE(MAX(SEQ) + 1, 1) AS SEQ
	   FROM TWORK_INFO_IVATXLCXULC_ADJ

	/* wms-inbound-invnrevision-sql-oracle.xml - selectIvat - 재고 정보 조회 SQL */
		SELECT *
		  FROM TWORK_INFO_IVAT A
		 INNER JOIN TWORK_INFO_IVATXLCXULC B
		    ON A.CTKEY = B.CTKEY
		   AND A.OWKEY = B.OWKEY
		   AND A.ICKEY = B.ICKEY
		   AND A.IVATKEY = B.IVATKEY
		 WHERE A.CTKEY            = #{ctkey}
           AND A.OWKEY            = #{owkey}
           AND B.LCKEY 			  = #{lckey}
           AND A.IVATKEY 		  = #{ivatkey}

	/* wms-inbound-invnrevision-sql-oracle.xml - selectIcMap - 상품 정보 SQL */
		SELECT *
		  FROM TWORK_MST_IC
		 WHERE CTKEY = #{ctkey}
           AND OWKEY = #{owkey}
           AND ICKEY = #{ickey}
